    /**
    * Calls:
    * 1 - (401) GET:/api/task/logg/{id}
    * 2 - (200) GET:/api/task/logg/{id}
    * 3 - (401) POST:/api/ekstern/pensjon/hent-barnetrygd
    * Found 1 potential fault of type-code 205
    * Using 1 example:
    *   (-) BODY -> 2020-12-01
    */
    @Test @Timeout(60)
    public void test_93_postOnHent_barnetrygdAuthenticatedButWronglyToldNot() throws Exception {
        
        final String token_Kode6 = given()
                .contentType("application/x-www-form-urlencoded")
                .body("name=Kode6&grant_type=client_credentials&code=foo&client_id=foo&client_secret=secret")
                .post("http://localhost:10122/azuread/token")
                .then().extract().response().path("access_token");
                
        final String auth_Kode6 = "Bearer " + token_Kode6;
        final String token_TaskRunner = given()
                .contentType("application/x-www-form-urlencoded")
                .body("name=TaskRunner&grant_type=client_credentials&code=foo&client_id=foo&client_secret=secret")
                .post("http://localhost:10122/azuread/token")
                .then().extract().response().path("access_token");
                
        final String auth_TaskRunner = "Bearer " + token_TaskRunner;
        
        given().accept("*/*")
                .header("x-EMextraHeader123", "")
                .header("Authorization", auth_Kode6) // Kode6
                .get(baseUrlOfSut + "/api/task/logg/924?page=706")
                .then()
                .statusCode(401)
                .assertThat()
                .contentType("text/html");
        
        given().accept("*/*")
                .header("x-EMextraHeader123", "")
                .header("Authorization", auth_TaskRunner) // TaskRunner
                .get(baseUrlOfSut + "/api/task/logg/610")
                .then()
                .statusCode(200)
                .assertThat()
                .contentType("application/json")
                .body("'data'", nullValue())
                .body("'status'", containsString("FEILET"))
                .body("'melding'", containsString("Henting av tasklogg feilet."))
                .body("'frontendFeilmelding'", containsString("Henting av tasklogg feilet."));
        
        // Fault205. Wrongly Not Recognized as Authenticated.
        given().accept("application/json")
                .header("x-EMextraHeader123", "")
                .header("Authorization", auth_TaskRunner) // TaskRunner
                .contentType("application/json")
                .body(" { " + 
                    " \"ident\": \"tB41o\", " + 
                    " \"fraDato\": \"2020-12-01\" " + 
                    " } ")
                .post(baseUrlOfSut + "/api/ekstern/pensjon/hent-barnetrygd")
                .then()
                .statusCode(401)
                .assertThat()
                .contentType("application/json")
                .body("'servlet'", containsString("dispatcherServlet"))
                .body("'message'", containsString("Pensjon tjeneste kan kun kalles av pensjon eller innlogget bruker med FORVALTER rolle"))
                .body("'url'", containsString("/api/ekstern/pensjon/hent-barnetrygd"))
                .body("'status'", containsString("401"));
    }
    
    
